@@ -109,7 +109,15 @@ const fs = require("node:fs");
 const path = require("node:path");

 const configPath = path.join(process.env.HOME, ".openclaw", "openclaw.json");
+const stateDir = path.dirname(configPath);
 const config = {
+  gateway: {
+    mode: "local",
+    auth: {
